@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" loading="lazy" />
                    <div class="product-card-info">
                        <span class="product-card-name">@product.Name</span>
                        <span class="product-card-price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private CancellationTokenSource? _debounceCts;
    private CancellationTokenSource? _searchCts;

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce timer.
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _debounceCts = new CancellationTokenSource();
        var debounceToken = _debounceCts.Token;

        try
        {
            await Task.Delay(300, debounceToken);
        }
        catch (TaskCanceledException)
        {
            return; // User kept typing; wait for the next pause.
        }

        await ExecuteSearch();
    }

    private async Task ExecuteSearch()
    {
        var trimmed = _query.Trim();

        if (string.IsNullOrEmpty(trimmed))
        {
            _results = new();
            _hasSearched = false;
            _error = null;
            return;
        }

        // Cancel any in-flight search so we don't apply stale results.
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = new CancellationTokenSource();
        var token = _searchCts.Token;

        _isLoading = true;
        _error = null;

        try
        {
            _results = await ProductService.SearchAsync(trimmed, token);
            _hasSearched = true;
        }
        catch (OperationCanceledException)
        {
            return; // A newer search superseded this one.
        }
        catch (Exception ex)
        {
            _results = new();
            _error = ex.Message;
        }
        finally
        {
            if (!token.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }
    }

    private async Task RetrySearch()
    {
        await ExecuteSearch();
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    public void Dispose()
    {
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _searchCts?.Cancel();
        _searchCts?.Dispose();
    }
}

